/*
  Global Design System
  - Modern dark-mode corporate style
  - Based on Space Grotesk (headings) and Source Sans 3 (body)
  - Color palette aligned with provided design reference
*/

@import url("https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@400;500;600;700&family=Source+Sans+3:wght@300;400;500;600&family=Source+Code+Pro:wght@400;500&display=swap");

:root {
  /* Color palette */
  --color-bg-page: #181d23;        /* Deep charcoal background */
  --color-bg-elevated: #252c33;    /* Header and elevated sections */
  --color-border-subtle: #3a434c;  /* Hairline borders/dividers */
  --color-text-primary: #ffffff;   /* Primary text on dark */
  --color-text-muted: #a6b0bd;     /* Muted body copy */
  --color-text-soft: #d7dde5;      /* Softer light gray */
  --color-accent: #11c5b0;         /* Teal accent for actions */
  --color-accent-soft: #11c5b0;    /* Same accent, reserved for hover/focus */

  --color-success: #2ecc71;
  --color-error: #e74c3c;
  --color-warning: #f1c40f;
  --color-info: #3498db;

  /* Typography */
  --font-heading: "Space Grotesk", Helvetica, sans-serif;
  --font-body: "Source Sans 3", Arial, sans-serif;
  --font-code: "Source Code Pro", monospace;

  --font-size-h1: 3.5rem;  /* 56px */
  --font-size-h2: 2.25rem; /* 36px */
  --font-size-h3: 1.5rem;  /* 24px */
  --font-size-body: 1rem;  /* 16px */
  --font-size-small: 0.8125rem; /* 13px */

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.75;

  --font-weight-light: 300;
  --font-weight-regular: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  /* Spacing scale (8px baseline) */
  --space-0: 0;
  --space-1: 0.25rem;   /* 4px */
  --space-2: 0.5rem;    /* 8px */
  --space-3: 1rem;      /* 16px */
  --space-4: 1.5rem;    /* 24px */
  --space-5: 2rem;      /* 32px */
  --space-6: 3rem;      /* 48px */
  --space-7: 4rem;      /* 64px */

  --radius-sm: 4px;
  --radius-md: 8px;
  --radius-lg: 12px;

  --shadow-soft: 0 12px 30px rgba(0, 0, 0, 0.35);
  --shadow-subtle: 0 1px 3px rgba(0, 0, 0, 0.25);

  --transition-fast: 150ms ease-out;
  --transition-med: 200ms ease-out;

  --max-width-page: 1120px;
}

/* Reset / base */

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

html {
  font-size: 16px;
}

body {
  min-height: 100vh;
  background-color: var(--color-bg-page);
  color: var(--color-text-primary);
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  -webkit-font-smoothing: antialiased;
}

img {
  max-width: 100%;
  height: auto;
}

a {
  color: inherit;
  text-decoration: none;
}

a:hover,
a:focus-visible {
  color: inherit;
}

:focus-visible {
  outline: 2px solid var(--color-accent);
  outline-offset: 3px;
}

.page-wrapper {
  display: flex;
  flex-direction: column;
  min-height: 100vh;
}

.container {
  width: 100%;
  max-width: var(--max-width-page);
  margin: 0 auto;
  padding: 0 var(--space-3);
}

.site-main {
  flex: 1 0 auto;
  padding: var(--space-7) 0;
}

/* Typography helpers */

h1,
.h1 {
  font-family: var(--font-heading);
  font-size: var(--font-size-h1);
  line-height: var(--line-height-tight);
  font-weight: var(--font-weight-bold);
  margin: 0 0 var(--space-4);
}

h2,
.h2 {
  font-family: var(--font-heading);
  font-size: var(--font-size-h2);
  line-height: var(--line-height-tight);
  font-weight: var(--font-weight-semibold);
  margin: 0 0 var(--space-3);
}

h3,
.h3 {
  font-family: var(--font-heading);
  font-size: var(--font-size-h3);
  line-height: var(--line-height-tight);
  font-weight: var(--font-weight-semibold);
  margin: 0 0 var(--space-2);
}

p {
  margin: 0 0 var(--space-3);
}

.text-muted {
  color: var(--color-text-muted);
}

.text-small {
  font-size: var(--font-size-small);
}

code,
pre {
  font-family: var(--font-code);
}

/* Header */

.site-header {
  background-color: var(--color-bg-elevated);
  color: var(--color-text-primary);
  box-shadow: var(--shadow-subtle);
}

/* Top utility bar (Book consultation / Contact) */

.top-bar {
  border-bottom: 1px solid var(--color-border-subtle);
  background-color: #181d23;
  font-size: var(--font-size-small);
}

.top-bar-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  min-height: 40px;
}

.top-bar-left {
  display: flex;
  align-items: center;
  gap: var(--space-2);
  color: var(--color-text-muted);
}

.top-link {
  text-transform: uppercase;
  letter-spacing: 0.14em;
  font-weight: var(--font-weight-medium);
  color: var(--color-text-soft);
  transition: color var(--transition-fast);
}

.top-link:hover,
.top-link:focus-visible {
  color: var(--color-accent);
}

.top-divider {
  opacity: 0.6;
}

/* Main header with brand + primary navigation */

.main-header {
  border-bottom: 1px solid var(--color-border-subtle);
}

.header-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  min-height: 72px;
  gap: var(--space-4);
}

.brand {
  display: inline-flex;
  align-items: center;
  font-family: var(--font-heading);
  font-size: 0.9375rem;
  font-weight: var(--font-weight-bold);
  letter-spacing: 0.22em;
  text-transform: uppercase;
  color: var(--color-text-primary);
  white-space: nowrap;
}

.brand-primary {
  padding: var(--space-1) 0;
}

.primary-nav {
  flex: 1 1 auto;
}

.nav-list {
  display: flex;
  flex-wrap: wrap;
  justify-content: flex-end;
  align-items: center;
  gap: var(--space-4);
  list-style: none;
  margin: 0;
  padding: 0;
}

.nav-item {
  flex: 0 0 auto;
}

.nav-link {
  position: relative;
  display: inline-block;
  padding: var(--space-2) 0;
  font-family: var(--font-heading);
  font-size: 0.875rem;
  text-transform: uppercase;
  letter-spacing: 0.16em;
  font-weight: var(--font-weight-medium);
  color: var(--color-text-soft);
  transition: color var(--transition-fast);
}

.nav-link::after {
  content: "";
  position: absolute;
  left: 0;
  bottom: 0;
  width: 0;
  height: 2px;
  background-color: var(--color-accent);
  transition: width var(--transition-med);
}

.nav-link:hover,
.nav-link:focus-visible {
  color: #ffffff;
}

.nav-link:hover::after,
.nav-link:focus-visible::after {
  width: 100%;
}

.nav-link.is-active {
  color: #ffffff;
}

.nav-link.is-active::after {
  width: 100%;
}

/* Footer */

.site-footer {
  background-color: #181d23;
  color: var(--color-text-soft);
  border-top: 1px solid var(--color-border-subtle);
  padding: var(--space-6) 0 var(--space-4);
  flex-shrink: 0;
}

.footer-inner {
  display: flex;
  flex-direction: column;
  gap: var(--space-5);
}

.footer-top {
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-5);
  justify-content: space-between;
}

.footer-brand {
  max-width: 280px;
}

.footer-logo {
  font-family: var(--font-heading);
  font-size: 0.9375rem;
  letter-spacing: 0.22em;
  text-transform: uppercase;
  font-weight: var(--font-weight-bold);
  margin-bottom: var(--space-2);
  color: #ffffff;
}

.footer-tagline {
  font-size: var(--font-size-small);
  color: var(--color-text-muted);
  line-height: var(--line-height-relaxed);
}

.footer-links-grid {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: var(--space-5);
  min-width: 0;
}

.footer-column {
  min-width: 0;
}

.footer-heading {
  font-family: var(--font-heading);
  font-size: 0.875rem;
  text-transform: uppercase;
  letter-spacing: 0.18em;
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-soft);
  margin: 0 0 var(--space-2);
}

.footer-nav-list {
  list-style: none;
  margin: 0;
  padding: 0;
}

.footer-nav-list li + li {
  margin-top: var(--space-1);
}

.footer-link {
  font-size: var(--font-size-small);
  color: var(--color-text-muted);
  transition: color var(--transition-fast);
}

.footer-link:hover,
.footer-link:focus-visible {
  color: var(--color-accent);
}

.footer-bottom {
  border-top: 1px solid var(--color-border-subtle);
  padding-top: var(--space-3);
  display: flex;
  align-items: center;
  justify-content: space-between;
  font-size: var(--font-size-small);
  color: var(--color-text-muted);
}

.footer-copy {
  margin: 0;
}

/* Responsive layout */

@media (max-width: 1024px) {
  .nav-list {
    gap: var(--space-3);
  }
}

@media (max-width: 768px) {
  .top-bar-inner {
    justify-content: center;
  }

  .header-inner {
    flex-direction: column;
    align-items: flex-start;
    padding-top: var(--space-3);
    padding-bottom: var(--space-3);
  }

  .primary-nav {
    width: 100%;
  }

  .nav-list {
    justify-content: flex-start;
    row-gap: var(--space-1);
    column-gap: var(--space-3);
  }

  .footer-top {
    flex-direction: column;
  }

  .footer-links-grid {
    grid-template-columns: 1fr 1fr;
  }
}

@media (max-width: 600px) {
  .container {
    padding-left: var(--space-2);
    padding-right: var(--space-2);
  }

  .nav-list {
    flex-direction: column;
    align-items: flex-start;
  }

  .footer-links-grid {
    grid-template-columns: 1fr;
  }

  .site-main {
    padding-top: var(--space-5);
    padding-bottom: var(--space-5);
  }
}

/* Utility class for visually-hidden text, useful for a11y if needed */

.visually-hidden {
  border: 0;
  clip: rect(0 0 0 0);
  height: 1px;
  margin: -1px;
  overflow: hidden;
  padding: 0;
  position: absolute;
  width: 1px;
}
